revision.text:
/* {{pp-template}} */
#skip-to-top-button,
#skip-to-bottom-button {
	position: fixed;
	bottom: 8px;
	z-index: 50;
}

#skip-to-top-button:hover,
#skip-to-bottom-button:hover {
	filter: brightness(1.05);
}

#skip-to-top-button:active,
#skip-to-bottom-button:active {
	filter: brightness(0.95);
}

#skip-to-bottom-button {
	right: 8px;
}

#skip-to-top-button {
	right: 64px;
}

/* Vector 2022 fixes */
body.skin-vector-2022 #skip-to-bottom-button,
body.skin-vector-2022 #skip-to-top-button {
	position: sticky;
	top: 92%;
	float: right;
	margin: auto 6px;
	right: 0;
	opacity: 0.8;
}

/* Minerva fixes - avoid intersections with [[mw:Help:Growth/Tools/Help panel]] */
body.skin-minerva #skip-to-bottom-button,
body.skin-minerva #skip-to-top-button {
	position: sticky;
	top: 92%;
	float: left;
	margin: auto 6px;
	left: 0;
	opacity: 0.8;
}

@media screen {
	html.skin-theme-clientpref-night #skip-to-top-button,
	html.skin-theme-clientpref-night #skip-to-bottom-button {
		filter: brightness(0.9) invert(1) hue-rotate(180deg);
	}
	html.skin-theme-clientpref-night #skip-to-top-button:hover,
	html.skin-theme-clientpref-night #skip-to-bottom-button:hover {
		filter: brightness(0.85) invert(1) hue-rotate(180deg);
	}
	html.skin-theme-clientpref-night #skip-to-top-button:active,
	html.skin-theme-clientpref-night #skip-to-bottom-button:active {
		filter: brightness(0.95) invert(1) hue-rotate(180deg);
	}
}

@media screen and (prefers-color-scheme: dark) {
	html.skin-theme-clientpref-os #skip-to-top-button,
	html.skin-theme-clientpref-os #skip-to-bottom-button {
		filter: brightness(0.9) invert(1) hue-rotate(180deg);
	}
	html.skin-theme-clientpref-os #skip-to-top-button:hover,
	html.skin-theme-clientpref-os #skip-to-bottom-button:hover {
		filter: brightness(0.85) invert(1) hue-rotate(180deg);
	}
	html.skin-theme-clientpref-os #skip-to-top-button:active,
	html.skin-theme-clientpref-os #skip-to-bottom-button:active {
		filter: brightness(0.95) invert(1) hue-rotate(180deg);
	}
}

